import{_ as t,a,b as d,c as i}from"./chunks/查询额度成功.BYPQR2qF.js";import{_ as o,o as r,c as l,a2 as n}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"WebDAV Channel ထည့်သွင်းခြင်း","description":"","frontmatter":{},"headers":[],"relativePath":"my/upload/webdav.md","filePath":"my/upload/webdav.md","lastUpdated":1781962217000}'),s={name:"my/upload/webdav.md"};function c(p,e,h,u,b,m){return r(),l("div",null,[...e[0]||(e[0]=[n('<h1 id="webdav-channel-ထည့်သွင်းခြင်း" tabindex="-1">WebDAV Channel ထည့်သွင်းခြင်း <a class="header-anchor" href="#webdav-channel-ထည့်သွင်းခြင်း" aria-label="Permalink to &quot;WebDAV Channel ထည့်သွင်းခြင်း&quot;">​</a></h1><h2 id="ဘယ်အချိန်မှာ-သုံးသင့်လဲ" tabindex="-1">ဘယ်အချိန်မှာ သုံးသင့်လဲ <a class="header-anchor" href="#ဘယ်အချိန်မှာ-သုံးသင့်လဲ" aria-label="Permalink to &quot;ဘယ်အချိန်မှာ သုံးသင့်လဲ&quot;">​</a></h2><p>WebDAV channel ကို ဒီလိုအခြေအနေတွေမှာသုံးပါ:</p><ul><li>WebDAV endpoint ပေးတဲ့ NAS, cloud drive, object storage service ရှိလျှင်။</li><li>uploaded images တွေကို ကိုယ်ပိုင် WebDAV directory ထဲသိမ်းချင်လျှင်။</li><li>credentials တွေကို frontend မှာကြာရှည်မဖော်ပြဘဲ D1 <code>upload_channels</code> table ထဲသိမ်းချင်လျှင်။</li></ul><h2 id="စမလုပ်ခင်-လိုအပ်တာတွေ" tabindex="-1">စမလုပ်ခင် လိုအပ်တာတွေ <a class="header-anchor" href="#စမလုပ်ခင်-လိုအပ်တာတွေ" aria-label="Permalink to &quot;စမလုပ်ခင် လိုအပ်တာတွေ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>လိုအပ်ချက်</th><th>အသုံးပြုပုံ</th></tr></thead><tbody><tr><td>WebDAV Endpoint</td><td>server-side WebDAV URL၊ ဥပမာ <code>https://nas.example.com/dav</code>။</td></tr><tr><td>Username</td><td>WebDAV service ကို sign in ဝင်ရန်။</td></tr><tr><td>Password</td><td>WebDAV service ကို sign in ဝင်ရန်။</td></tr><tr><td>Authentication mode</td><td>default က <code>Basic</code> ဖြစ်သည်။ server ကလိုအပ်မှသာ <code>Digest</code> သို့မဟုတ် auto negotiation သုံးပါ။</td></tr><tr><td>Storage directory</td><td>files သိမ်းမယ့် directory။ default က <code>imgbed</code>။</td></tr></tbody></table><h2 id="ဘယ်နေရာမှာ-ထည့်မလဲ" tabindex="-1">ဘယ်နေရာမှာ ထည့်မလဲ <a class="header-anchor" href="#ဘယ်နေရာမှာ-ထည့်မလဲ" aria-label="Permalink to &quot;ဘယ်နေရာမှာ ထည့်မလဲ&quot;">​</a></h2><ol><li>System Settings ကိုဖွင့်ပါ။</li><li>Upload Settings ကိုသွားပါ။</li><li>ညာဘက်အပေါ်ထောင့်က Add Channel ကိုနှိပ်ပါ။</li><li><code>WebDAV</code> ကိုရွေးပါ။</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>အသုံးပြုပုံ</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>ဒီ WebDAV channel အတွက် မှတ်မိလွယ်တဲ့အမည်၊ ဥပမာ <code>koofr</code> သို့မဟုတ် <code>nas</code>။</td><td>Yes</td></tr><tr><td>Endpoint</td><td><code>https://</code> ပါတဲ့ WebDAV endpoint အပြည့်အစုံ။</td><td>Yes</td></tr><tr><td>Username</td><td>WebDAV login username။</td><td>Yes</td></tr><tr><td>Password</td><td>WebDAV login password။</td><td>Yes</td></tr><tr><td>Authentication mode</td><td>များသောအားဖြင့် <code>Basic</code>။ server က digest authentication လိုလျှင် <code>Digest</code> သုံးပါ။</td><td>Yes</td></tr><tr><td>Storage directory</td><td>files သိမ်းမယ့် directory။ default က <code>imgbed</code>။</td><td>No</td></tr></tbody></table><h2 id="ဥပမာ-fie-nl-tab-digital" tabindex="-1">ဥပမာ: fie.nl.tab.digital <a class="header-anchor" href="#ဥပမာ-fie-nl-tab-digital" aria-label="Permalink to &quot;ဥပမာ: fie.nl.tab.digital&quot;">​</a></h2><h3 id="_1-app-password-ဖန်တီးပါ" tabindex="-1">1. App Password ဖန်တီးပါ <a class="header-anchor" href="#_1-app-password-ဖန်တီးပါ" aria-label="Permalink to &quot;1. App Password ဖန်တီးပါ&quot;">​</a></h3><p>account security settings ကိုဖွင့်ပြီး application passwords ကိုရှာကာ app password အသစ်ဖန်တီးပါ။</p><p><img src="'+t+'" alt="Create an app password" loading="lazy"></p><p>ဖန်တီးပြီးရင် app password အသစ်ကို copy လုပ်ပြီးသိမ်းပါ။ များသောအားဖြင့် တစ်ကြိမ်ပဲပြပါမယ်။</p><p><img src="'+a+'" alt="Save the new app password" loading="lazy"></p><h3 id="_2-imgbed-မှာ-webdav-configuration-ဖြည့်ပါ" tabindex="-1">2. ImgBed မှာ WebDAV Configuration ဖြည့်ပါ <a class="header-anchor" href="#_2-imgbed-မှာ-webdav-configuration-ဖြည့်ပါ" aria-label="Permalink to &quot;2. ImgBed မှာ WebDAV Configuration ဖြည့်ပါ&quot;">​</a></h3><p>ImgBed ကိုပြန်သွားပြီး WebDAV channel ထည့်ပါ:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Endpoint</td><td><code>https://fie.nl.tab.digital/</code> ကပေးတဲ့ WebDAV URL။</td></tr><tr><td>Username</td><td>သင့် WebDAV username။</td></tr><tr><td>Password</td><td>မကြာသေးခင်ဖန်တီးထားတဲ့ app password။</td></tr><tr><td>Authentication mode</td><td>အများစုမှာ <code>Basic</code> နဲ့စပါ။</td></tr><tr><td>Storage directory</td><td>default က <code>imgbed</code>; custom directory လည်းသုံးနိုင်သည်။</td></tr></tbody></table><p><img src="'+d+'" alt="Fill in the configuration" loading="lazy"></p><h2 id="file-ကြီး-upload-လုပ်ပုံ" tabindex="-1">File ကြီး Upload လုပ်ပုံ <a class="header-anchor" href="#file-ကြီး-upload-လုပ်ပုံ" aria-label="Permalink to &quot;File ကြီး Upload လုပ်ပုံ&quot;">​</a></h2><p>WebDAV channel က အခု real session-based chunked upload ကိုသုံးပါတယ်။</p><p>file သေးတွေကို complete file တစ်ခုအဖြစ် upload လုပ်ပါတယ်။ 64 MiB ထက်ကြီးတဲ့ files တွေကို 10 MiB ဝန်းကျင် chunks တွေအဖြစ် ခွဲပြီး remote chunk directory ထဲ upload လုပ်ပါမယ်။</p><p>WebDAV service က <code>partial update</code> သို့မဟုတ် offset-based writes ကို support လုပ်ဖို့မလိုပါ။ ImgBed က remote server ပေါ်မှာ chunks တွေကို file ကြီးတစ်ခုအဖြစ် merge မလုပ်ပါ။ chunk manifest သိမ်းပြီး file request လာတဲ့အခါ chunks တွေကိုအစဉ်လိုက်ဖတ်ပါမယ်။</p><table tabindex="0"><thead><tr><th>File Size</th><th>Upload Method</th><th>Remote Storage Layout</th></tr></thead><tbody><tr><td>64 MiB သို့မဟုတ် ပိုသေး</td><td>Normal upload</td><td>complete file တစ်ခု</td></tr><tr><td>64 MiB ထက်ကြီး</td><td>Real session chunked upload</td><td>chunk files အများကြီးပါသော chunk directory</td></tr></tbody></table><p>chunk directory က remote storage layout ကိုပဲသက်ရောက်ပါတယ်။ ImgBed ထဲက file URL မပြောင်းပါ။ users တွေက မူလ <code>/file/...</code> link ကနေ file ကိုဆက်လက် access လုပ်နိုင်ပါတယ်။</p><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><ol><li>Upload Settings ကိုဖွင့်ပါ။</li><li>Add Channel ကိုနှိပ်ပါ။</li><li><code>WebDAV</code> ကိုရွေးပါ။</li><li>မှတ်မိလွယ်တဲ့ channel name ထည့်ပါ၊ ဥပမာ <code>koofr</code>။</li><li>WebDAV endpoint ထည့်ပါ၊ ဥပမာ <code>https://app.koofr.net/dav/Koofr</code>။</li><li>username နဲ့ password ထည့်ပါ။</li><li>authentication mode ကို default <code>Basic</code> အတိုင်းထားပါ။</li><li>storage directory ကို <code>imgbed</code> အတိုင်းထားနိုင်ပြီး ကိုယ်ပိုင် directory လည်းထည့်နိုင်ပါတယ်။</li><li>Save ကိုနှိပ်ပါ။</li><li>Save ပြီးနောက် channel card စစ်ပါ၊ capacity query ရနိုင်လျှင် query လုပ်ပါ၊ test file တစ်ခု upload လုပ်ပါ။</li></ol><h2 id="စစ်ဆေးနည်း" tabindex="-1">စစ်ဆေးနည်း <a class="header-anchor" href="#စစ်ဆေးနည်း" aria-label="Permalink to &quot;စစ်ဆေးနည်း&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>စစ်ဆေးပုံ</th></tr></thead><tbody><tr><td>Channel card appears</td><td>Save ပြီးနောက် Upload Settings မှာ WebDAV channel card ပေါ်လာရပါမယ်။</td></tr><tr><td>Channel is enabled</td><td>card ရဲ့ ညာဘက်အပေါ် switch က on ဖြစ်ရပါမယ်။</td></tr><tr><td>Credentials are saved</td><td>detail view မှာ Endpoint, username, authentication mode, storage directory တွေမြင်ရပါမယ်။</td></tr><tr><td>Small file upload works</td><td>test image upload လုပ်ပြီး WebDAV directory ထဲ file ပေါ်လာလားစစ်ပါ။</td></tr><tr><td>Large file rule works</td><td>64 MiB ထက်ကြီးတဲ့ files တွေက chunked upload သုံးပြီး remote chunk directory ဖန်တီးရပါမယ်။</td></tr><tr><td>Capacity query works</td><td>server က capacity information support လုပ်ရင် used နဲ့ total capacity ပြပါမယ်။</td></tr></tbody></table><p><img src="'+i+`" alt="Quota query succeeded" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="webdav-file-ကြီးတွေက-chunk-directory-ဘာကြောင့်ဖန်တီးလဲ" tabindex="-1">WebDAV file ကြီးတွေက chunk directory ဘာကြောင့်ဖန်တီးလဲ? <a class="header-anchor" href="#webdav-file-ကြီးတွေက-chunk-directory-ဘာကြောင့်ဖန်တီးလဲ" aria-label="Permalink to &quot;WebDAV file ကြီးတွေက chunk directory ဘာကြောင့်ဖန်တီးလဲ?&quot;">​</a></h3><p>ဒါက file ကြီးတွေအတွက် လက်ရှိ storage method ဖြစ်ပါတယ်။</p><p>64 MiB ထက်ကြီးတဲ့ files တွေကို remote side မှာ file ကြီးတစ်ခုအဖြစ် merge မလုပ်ပါ။ chunk directory အဖြစ်သိမ်းပြီး ImgBed က chunk manifest ကို record လုပ်ကာ complete content ကို chunks အစဉ်လိုက်ဖတ်ပြီးပြန်ပေးပါတယ်။</p><h3 id="large-file-upload-fail-ဖြစ်ရင်-အရင်ဆုံးဘာစစ်ရမလဲ" tabindex="-1">large file upload fail ဖြစ်ရင် အရင်ဆုံးဘာစစ်ရမလဲ? <a class="header-anchor" href="#large-file-upload-fail-ဖြစ်ရင်-အရင်ဆုံးဘာစစ်ရမလဲ" aria-label="Permalink to &quot;large file upload fail ဖြစ်ရင် အရင်ဆုံးဘာစစ်ရမလဲ?&quot;">​</a></h3><p>Endpoint, username, password, storage directory ကိုအရင်စစ်ပါ။ ပြီးရင် WebDAV service က directory creation, file writing, file reading ကို allow လုပ်လား confirm လုပ်ပါ။</p><p>capacity query fail ဖြစ်ပေမယ့် small file upload အလုပ်လုပ်ရင် server က capacity reporting ကိုမထောက်ပံ့တာ သို့မဟုတ် ကန့်သတ်ထားတာဖြစ်နိုင်ပါတယ်။ upload မရဘူးလို့ တန်းမဆိုလိုပါ။</p><h3 id="ဘယ်-authentication-mode-သုံးရမလဲ" tabindex="-1">ဘယ် authentication mode သုံးရမလဲ? <a class="header-anchor" href="#ဘယ်-authentication-mode-သုံးရမလဲ" aria-label="Permalink to &quot;ဘယ် authentication mode သုံးရမလဲ?&quot;">​</a></h3><p><code>Basic</code> နဲ့စပါ။</p><p>server က digest authentication လိုတယ်လို့တိတိကျကျပြထားရင် <code>Digest</code> သုံးပါ။</p><p>မသေချာရင် automatic negotiation ကိုသုံးပါ။</p><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebDAV endpoint, username, password ပြင်ဆင်ပါ</span></span>
<span class="line"><span>-&gt; Upload Settings ဖွင့်ပါ</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; WebDAV ရွေးပါ</span></span>
<span class="line"><span>-&gt; Endpoint / username / password ထည့်ပါ</span></span>
<span class="line"><span>-&gt; authentication mode ကို default Basic ထားပါ</span></span>
<span class="line"><span>-&gt; storage directory ကို default imgbed ထားပါ</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; capacity query</span></span>
<span class="line"><span>-&gt; test file upload</span></span></code></pre></div>`,44)])])}const k=o(s,[["render",c]]);export{y as __pageData,k as default};
